"""
AGROCENTRAL — Dashboard Cloud (Railway)
========================================
Sincronizado con agrocentral_dashboard.py local — mismo HTML frontend.

requirements.txt:
    flask
    psycopg2-binary
    gunicorn

Procfile:
    web: gunicorn agrocentral_cloud_dashboard:app --bind 0.0.0.0:$PORT
"""

import os, json, base64, traceback
import psycopg2
import psycopg2.extras
from flask import Flask, jsonify, render_template_string, request, make_response, redirect
from datetime import datetime

app = Flask(__name__)

# Usuarios
USERS = {
    "ariel":    os.environ.get("DASHBOARD_PASSWORD_ARIEL",  "agrocentral2026"),
    "jere":     os.environ.get("DASHBOARD_PASSWORD_JERE",   "jere2026"),
    "ale":      os.environ.get("DASHBOARD_PASSWORD_ALE",    "ale2026"),
}

# HTML embebido en base64 — mismo que el dashboard local
_HTML_B64 = ""

def get_html():
    return base64.b64decode(_HTML_B64).decode("utf-8")

# Auth
def get_session_user(req):
    token = req.cookies.get("agro_session", "")
    if not token or ":" not in token:
        return None
    username, stored = token.split(":", 1)
    if username in USERS and stored == str(abs(hash(USERS[username] + username)))[:12]:
        return username
    return None

def check_auth(req):
    return get_session_user(req) is not None

def make_token(username):
    return f"{username}:{str(abs(hash(USERS[username] + username)))[:12]}"

# DB
def get_db_url():
    url = os.environ.get("DATABASE_URL", "")
    if url.startswith("postgres://"):
        url = url.replace("postgres://", "postgresql://", 1)
    return url

def get_conn():
    return psycopg2.connect(get_db_url(), sslmode="require")

def init_db():
    with get_conn() as conn:
        with conn.cursor() as cur:
            cur.execute("""
                CREATE TABLE IF NOT EXISTS items (
                    id TEXT PRIMARY KEY,
                    sku TEXT,
                    title TEXT,
                    data JSONB,
                    updated_at TIMESTAMP DEFAULT NOW()
                )
            """)
            cur.execute("""
                CREATE TABLE IF NOT EXISTS reviews (
                    item_id TEXT PRIMARY KEY,
                    usuario TEXT,
                    fecha TEXT,
                    ts TIMESTAMP DEFAULT NOW()
                )
            """)
            cur.execute("""
                CREATE TABLE IF NOT EXISTS glosario_overrides (
                    sku TEXT PRIMARY KEY,
                    principio_activo TEXT,
                    concentracion TEXT,
                    usuario TEXT,
                    fecha TEXT,
                    ts TIMESTAMP DEFAULT NOW()
                )
            """)
            # Migracion: agregar columnas si no existen (por si la tabla fue creada con otros nombres)
            for col, typedef in [("usuario", "TEXT"), ("fecha", "TEXT"), ("ts", "TIMESTAMP DEFAULT NOW()")]:
                try:
                    cur.execute(f"ALTER TABLE reviews ADD COLUMN IF NOT EXISTS {col} {typedef}")
                except Exception:
                    pass
            cur.execute("""
                CREATE TABLE IF NOT EXISTS meta (
                    key TEXT PRIMARY KEY,
                    value TEXT
                )
            """)
            cur.execute("""
                CREATE TABLE IF NOT EXISTS active_viewers (
                    usuario TEXT PRIMARY KEY,
                    item_id TEXT,
                    title   TEXT,
                    ts      TIMESTAMP DEFAULT NOW()
                )
            """)
        conn.commit()
    print("DB inicializada.")

try:
    init_db()
except Exception as e:
    print(f"init_db error: {e}")

