@app.route("/upload", methods=["POST"])
def upload_data():
    """Endpoint llamado por agrocentral_uploader.py"""
    auth = request.headers.get("X-Upload-Key", "")
    upload_key = os.environ.get("UPLOAD_KEY", "agrocentral_upload_2026")
    if auth != upload_key:
        return jsonify({"ok": False, "msg": "No autorizado"}), 401
    try:
        payload     = request.get_json()
        items       = payload.get("items", [])
        last_update = payload.get("last_update", datetime.now().isoformat())
        with get_conn() as conn:
            with conn.cursor() as cur:
                # Borrar todos los items viejos antes de subir los nuevos
                cur.execute("DELETE FROM items")
                for it in items:
                    cur.execute("""
                        INSERT INTO items (id, sku, title, data)
                        VALUES (%s, %s, %s, %s)
                        ON CONFLICT (id) DO UPDATE
                        SET sku=EXCLUDED.sku, title=EXCLUDED.title,
                            data=EXCLUDED.data, updated_at=NOW()
                    """, (it.get("id",""), it.get("sku",""), it.get("title",""),
                          json.dumps(it, ensure_ascii=False)))
                cur.execute("""
                    INSERT INTO meta (key, value) VALUES ('last_update', %s)
                    ON CONFLICT (key) DO UPDATE SET value=EXCLUDED.value
                """, (last_update,))
            conn.commit()
        return jsonify({"ok": True, "uploaded": len(items)})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e), "trace": traceback.format_exc()}), 500


@app.route("/api/glosario/<sku>", methods=["POST"])
def api_glosario_update(sku):
    """Jere/Ale corrigen PA y concentración de un producto."""
    username = get_session_user(request)
    if not username:
        return jsonify({"ok": False}), 401
    data = request.get_json() or {}
    pa   = (data.get("principio_activo") or "").strip().lower()
    conc = (data.get("concentracion") or "").strip()
    nc   = (data.get("nombre_comercial") or "").strip()
    if not pa:
        return jsonify({"ok": False, "msg": "principio_activo requerido"}), 400
    # Agregar columna nombre_comercial si no existe (migración automática)
    fecha = datetime.now().strftime("%d/%m/%Y %H:%M")
    try:
        with get_conn() as conn:
            with conn.cursor() as cur:
                try:
                    cur.execute("ALTER TABLE glosario_overrides ADD COLUMN IF NOT EXISTS nombre_comercial TEXT")
                except: pass
                cur.execute("""
                    INSERT INTO glosario_overrides (sku, principio_activo, concentracion, nombre_comercial, usuario, fecha)
                    VALUES (%s, %s, %s, %s, %s, %s)
                    ON CONFLICT (sku) DO UPDATE
                    SET principio_activo=EXCLUDED.principio_activo,
                        concentracion=EXCLUDED.concentracion,
                        nombre_comercial=EXCLUDED.nombre_comercial,
                        usuario=EXCLUDED.usuario,
                        fecha=EXCLUDED.fecha,
                        ts=NOW()
                """, (sku, pa, conc or None, nc or None, username, fecha))
            conn.commit()
        return jsonify({"ok": True, "sku": sku, "pa": pa, "conc": conc, "usuario": username})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)}), 500

