@app.route("/api/export/excel")
def export_excel():
    if not check_auth(request):
        return jsonify({}), 401
    try:
        import openpyxl
        from openpyxl.styles import Font, PatternFill, Alignment
        from io import BytesIO

        with get_conn() as conn:
            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                cur.execute("SELECT data FROM items ORDER BY title")
                rows = cur.fetchall()
                cur.execute("SELECT item_id, usuario, fecha FROM reviews")
                rev_rows = cur.fetchall()

        reviews_map = {r["item_id"]: r for r in rev_rows}

        wb = openpyxl.Workbook()
        ws = wb.active
        ws.title = "Competencia"

        # Encabezados
        headers = ["SKU", "ID", "Titulo", "Mi Precio", "Min Competidor", "Precio Sugerido", "Dif %",
                   "Principio Activo", "Concentracion", "Presentacion",
                   "Tipo Envio", "Paga Envio", "Comision ML", "Vendidos",
                   "Grupo", "Cant Competidores", "Comp Nuevos",
                   "Mejor Competidor", "Precio Mejor Comp", "Stock Mejor Comp",
                   "Vendedor Comp", "Revisado por", "Fecha revision"]

        header_fill = PatternFill("solid", fgColor="1a5c30")
        header_font = Font(color="FFFFFF", bold=True)

        for col, h in enumerate(headers, 1):
            cell = ws.cell(row=1, column=col, value=h)
            cell.fill = header_fill
            cell.font = header_font
            cell.alignment = Alignment(horizontal="center")

        # Colores por semaforo
        colors = {"verde": "c8e6c9", "amarillo": "fff9c4", "rojo": "ffcdd2", "gris": "f5f5f5"}

        row_num = 2
        for row in rows:
            d = row["data"]
            if isinstance(d, str):
                d = json.loads(d)
            if d.get("listing_type_id") != "gold_special":
                continue
            if any(t.get("id") == "INSTALLMENTS_CAMPAIGN" for t in d.get("sale_terms", [])):
                continue

            comps = d.get("competidores", [])
            # dedup
            seen = set()
            unique = []
            for c in comps:
                if c.get("id") not in seen:
                    seen.add(c.get("id"))
                    unique.append(c)
            comps = unique

            best = min(comps, key=lambda c: c.get("price") or 999999999) if comps else None
            has_exacto = any(c.get("match_type") == "exacto" for c in comps)
            grupo = "exacto" if has_exacto else ("equivalente" if comps else "ninguno")

            price = d.get("price") or 0
            min_comp = best["price"] if best else None
            dif_pct = round((price - min_comp) / min_comp * 100, 1) if min_comp and price else None

            rev = reviews_map.get(d.get("id", ""))

            precio_sugerido = round(min_comp * 1.03, 2) if min_comp else None
            values = [
                d.get("sku", ""),
                d.get("id", ""),
                d.get("title", ""),
                price,
                min_comp,
                precio_sugerido if d.get("semaforo") == "rojo" else "",
                dif_pct,
                d.get("principio_activo_glosario", ""),
                d.get("concentracion_glosario", ""),
                d.get("presentacion_glosario", ""),
                d.get("envio_tipo", ""),
                d.get("quien_paga", ""),
                d.get("comision"),
                d.get("sold_quantity", 0),
                grupo,
                len(comps),
                d.get("competidores_nuevos", 0),
                best["title"] if best else "",
                best["price"] if best else "",
                best.get("available_quantity", "") if best else "",
                best.get("seller_name", "") if best else "",
                rev["usuario"] if rev else "",
                rev["fecha"] if rev else "",
            ]

            fill_color = colors.get(d.get("semaforo", "gris"), "f5f5f5")
            fill = PatternFill("solid", fgColor=fill_color)

            for col, val in enumerate(values, 1):
                cell = ws.cell(row=row_num, column=col, value=val)
                cell.fill = fill

            row_num += 1

        # Ajustar anchos
        col_widths = [12, 14, 50, 14, 14, 14, 8, 20, 14, 12, 16, 12, 14, 10, 12, 8, 10, 40, 14, 8, 20, 14, 16]
        for i, w in enumerate(col_widths, 1):
            ws.column_dimensions[openpyxl.utils.get_column_letter(i)].width = w

        ws.freeze_panes = "A2"

        output = BytesIO()
        wb.save(output)
        output.seek(0)

        from flask import send_file
        return send_file(
            output,
            mimetype="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
            as_attachment=True,
            download_name=f"agrocentral_{datetime.now().strftime('%Y%m%d')}.xlsx"
        )
    except Exception as e:
        return jsonify({"error": str(e), "trace": traceback.format_exc()}), 500


@app.route("/api/active-viewers", methods=["GET"])
def get_active_viewers():
    if not check_auth(request):
        return jsonify({}), 401
    try:
        with get_conn() as conn:
            with conn.cursor(cursor_factory=psycopg2.extras.RealDictCursor) as cur:
                cur.execute("""
                    SELECT item_id, usuario, title, ts
                    FROM active_viewers
                    WHERE ts > NOW() - INTERVAL '90 seconds'
                """)
                rows = cur.fetchall()
        result = {}
        for r in rows:
            result[r["usuario"]] = {
                "item_id":  r["item_id"],
                "usuario":  r["usuario"],
                "title":    r["title"] or "",
                "ts":       r["ts"].isoformat() if r["ts"] else ""
            }
        return jsonify(result)
    except Exception as e:
        return jsonify({})

