@app.route("/api/admin/cleanup", methods=["POST"])
def admin_cleanup():
    """Limpia duplicados de competidores en la BD"""
    auth = request.headers.get("X-Upload-Key", "")
    upload_key = os.environ.get("UPLOAD_KEY", "agrocentral_upload_2026")
    if auth != upload_key:
        return jsonify({"ok": False, "msg": "No autorizado"}), 401
    try:
        with get_conn() as conn:
            with conn.cursor() as cur:
                cur.execute("SELECT id, data FROM items")
                rows = cur.fetchall()
        fixed = 0
        for item_id, data in rows:
            if isinstance(data, str):
                data = json.loads(data)
            comps = data.get("competidores", [])
            if not comps:
                continue
            seen = set()
            unique_comps = []
            for c in comps:
                cid = c.get("id", "")
                if cid and cid in seen:
                    continue
                seen.add(cid)
                unique_comps.append(c)
            if len(unique_comps) != len(comps):
                data["competidores"] = unique_comps
                with get_conn() as conn2:
                    with conn2.cursor() as cur2:
                        cur2.execute(
                            "UPDATE items SET data=%s WHERE id=%s",
                            (json.dumps(data, ensure_ascii=False), item_id)
                        )
                    conn2.commit()
                fixed += 1
        return jsonify({"ok": True, "items_fixed": fixed, "total_items": len(rows)})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e), "trace": traceback.format_exc()}), 500

